var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SERVICEBOT_NPC_NULL_NULL","text":{"KOREA":"주문하신 주류를 가져왔습니다, 손님.","JPN":"ご注文のお酒をお持ちしました、お客様。","ENG":"The drink you ordered, sir.","TWN":"客人，這是您點的酒。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERVICEBOT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERVICEBOT_NPC_NULL_NULL","text":{"KOREA":"저희 호텔에서 즐거운 추억을 만드시길 바랍니다. 필요하실 때 불러 주십시오.","JPN":"当ホテルで楽しい時間をお過ごしください。必要な際はいつでもお呼びください。","ENG":"I hope you have a pleasant stay at our hotel. Please don't hesitate to call if you need any assistance.","TWN":"祝您在本飯店留下美好的回憶，有任何需要請隨時找我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERVICEBOT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어머, 요즘에는 이런 데서도 로봇으로 서빙을 해 주네.","JPN":"あら、最近はこういうところでもロボットを使っているのね。","ENG":"Oh my. They've got robot waiters even in places like this these days, huh?","TWN":"哇，最近連這種地方也使用機器人提供服務嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"격식을 갖출 줄 모른다는 뜻이지.","JPN":"格式が高くないホテルってことだな。","ENG":"It shows they've got no class.","TWN":"一點都不像樣！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"돈을 비싸게 받으면 사람을 써야지, 어디서 저런 고물을.","JPN":"客から高い金をもらっているなら人でもてなすべきだろう。あんなポンコツを使いやがって。","ENG":"For the price we're paying, they ought to use real people. Not just some second-rate junk like that.","TWN":"想賺錢還捨不得花錢請真人，用那種廢鐵。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기는 로봇만 보면 그렇게 못마땅해 하더라.","JPN":"ダーリンってロボットを見ると機嫌が悪くなるよね。","ENG":"You always get so cranky whenever you see a robot, babe.","TWN":"親愛的怎麼看到機器人就那麼上火？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"그런데 이런 술 정말 시켜도 괜찮아? 내 한 달 월급보다 비쌀 것 같은데……?","JPN":"ていうか、本当にこんな高いお酒を頼んでもいいの？　あたしの給料より高そうだけど……？","ENG":"Anyway, are you sure we can order a drink like this? It's got to cost more than I make in a month…","TWN":"不過點這種酒沒問題嗎？應該比我一個月的薪水還貴吧……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 말했잖아. 나랑 있을 때는 가격표에 눈길 주지 말라고.","JPN":"言っただろ。僕といる時は金なんか気にしなくていいって。","ENG":"Hmph. I told you. Don't pay any attention to the price tag when you're with me.","TWN":"哼哼。我不是說過嗎？跟我在一起的時候不用在乎價錢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내가 돈을 벌어서 어디다 쓰겠어? 가지고 싶은 건 전부 가졌는데?","JPN":"僕が稼いだお金さ。欲しい物は何だって買えるし、すでに持っている。","ENG":"Where else am I going to spend my money? I've already got everything I've ever wanted.","TWN":"不然我賺那麼多錢是要花到哪裡？我想要的東西都已經有啦！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"샤레이드에서 가장 주목 받는 신흥 기업의 대표, 3대가 쓰고도 남을 재산에, 자기처럼 아름다운 애인까지.","JPN":"シャレードで最も注目されている新興企業の代表、桁違いの財産に、ハニーのような美しい恋人まで。","ENG":"I'm the CEO of the hottest unicorn company in Charade. My fortune will last more than three generations. And I'm dating the most beautiful woman in the world.","TWN":"身為在查雷德最受矚目的新興企業代表，我的錢三代都花不光，還有像親愛的這樣的美人伴身邊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"정말, 자기는 남들 다 듣는 데서 그런 부끄러운 말 하길 좋아하더라……","JPN":"もう～ダーリンったら～！　人目も気にしないで恥ずかしいこと言っちゃうんだから～！","ENG":"Aww, babe. You must enjoy making me blush, saying stuff like that in public all the time…","TWN":"討厭～親愛的真的很喜歡在人多的地方，說這種害羞的話……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아직 부끄러워하기에는 이르지. 지금부터가……","JPN":"恥ずかしがるにはまだはやい。これからが……","ENG":"It's a little early to get your skin flushed. We're just getting started…","TWN":"現在還不是害羞的時候，等下我……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하아, 업무 연락을 끊어 두는 걸 깜빡했군.","JPN":"はあ、業務連絡の通知を切っておくのをうっかり忘れてたな。","ENG":"Ugh… I forgot to turn off my work phone.","TWN":"哎呀，忘記把公務來電設為拒接。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"미안. 잠시 통화 좀 하고 올게.","JPN":"ごめんな。少し電話してくるよ。","ENG":"Sorry. I've got to take this call real quick.","TWN":"對不起，我去接個電話就回來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"신경 쓰지 말고 천천히 해. 난 괜찮으니까.","JPN":"あたしのことは気にしないで、ゆっくり話してきてね。","ENG":"Don't worry about me and take your time. I'm fine with it.","TWN":"沒關係，慢慢來，不用在意我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나, 무슨 일이지? 이 연락처로 업무 얘기는 안 하겠다고 하지 않았나?","JPN":"シェナ、今度は何だ？　この連絡先では仕事の話をしないと言ったはずだが。","ENG":"What is it, Shena? Didn't I make it clear I won't talk shop on this number?","TWN":"世娜，什麼事？我不是說公司的事不要打這支電話嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 성능 좋은 아티팩트를 두고 그렇게 맨얼굴로 다닐 거야?","JPN":"ふ～ん、性能の良いアーティファクトがあるのに、そんな素顔でいるつもりなんだ？","ENG":"Hmm, why go around with that boring face of yours when you've got such a great artifact at your disposal?","TWN":"嗯，你放著那麼棒的人造神器不用，用真面目示人喔？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 얼굴을 다른 사람으로 인식시키는 건 사업 때문에 만나는 놈들로 충분해.","JPN":"僕の顔を他人として認識させるのは、仕事のために会う奴らだけで十分だ。","ENG":"It's already enough that my business associates think I look like someone else.","TWN":"只有在生意場合我才會使用假面具。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하지만 저 사람은 예외야.","JPN":"あの人は特別だからな。","ENG":"She's an exception.","TWN":"但那個人是例外。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"나도 이제 내 개인적인 행복을 찾을 생각이다. 돈만 보고 달라붙는 여자들과는 재미 볼 만큼 봤어.","JPN":"僕はこれから自分の幸せを探すつもりだ。金が目当ての女たちと遊ぶのはもううんざりなんだよ。","ENG":"It's about time I find true personal happiness. I've had more than my fair share of fun with all those gold-diggers.","TWN":"我現在也打算尋找我個人的幸福，和那些見錢眼開的女生在一起已經沒什麼意思。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"있는 그대로의 나를 받아들여 줘, 뭐 이런 거야?","JPN":"ありのままの自分を受け入れてほしい、みたいな？","ENG":"Is this one of those \\"I want you to love me for who I really am\\" clichés?","TWN":"接受真實的我吧，像這樣嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"용건이나 어서 얘기해. 얼마나 급한 용무길래 내 휴가를 또 훼방 놓은 거지?","JPN":"用件を早く言え。どんな急用で僕の休暇を再び邪魔してきたんだ？","ENG":"Just cut to the chase already. What could be so urgent that you had to interrupt my vacation again?","TWN":"有什麼事快說！是有多急，打擾我休假？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"호라이즌을 처리하는 데 실패했어.","JPN":"ホライズンの処理に失敗したの。","ENG":"I failed to take care of Horizon.","TWN":"處理地平線任務失敗？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"타격조는? 전원 강화복까지 입혔는데 실패했다고?","JPN":"突撃隊は？　全員分の強化服まで支給してやったのに失敗しただと？","ENG":"But what about the strike squad? Everyone was wearing a power suit. And they still failed?","TWN":"打擊組呢？讓他們全都穿上強化服還失敗？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"으흥. 이를 어쩌나. 걔네들 전부 죽어 버렸어.","JPN":"うーん、どうしよう。あの子たち、全員死んじゃったの。","ENG":"Mm-hmm. The thing is… They're all dead.","TWN":"嗯哼，怎麼辦？那些人全都死了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……네 짓이로군. 셰나.","JPN":"……貴様の仕業だな、シェナ。","ENG":"…It was you, wasn't it. Shena.","TWN":"……是你做的對吧，世娜。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"인간이 싫어도 그렇지 회사 일까지 방해해도 되는 건가?","JPN":"人間が嫌いとはいえ、会社の仕事まで邪魔していいのか？","ENG":"I know you despise humans, but do you really have to disrupt my business too?","TWN":"你不喜歡人類我管不著，但怎麼可以妨礙公司的事？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 무슨 말씀을. 회사에 방해되지 않게 자장가로 재워 줬을 뿐이야.","JPN":"フフ、そんなこと言わないで。会社の邪魔にならないように子守唄で寝かせてやっただけよ。","ENG":"Heh. Don't be silly. I merely sang them a little lullaby so they won't become a liability for the business.","TWN":"呵呵～怎麼這麼說呢～我就是怕妨礙公司，才用催眠曲讓他們長眠的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"설마 호라이즌이 그 많은 수를 전부 상대했다고? 그 말을 나더러 믿으란 건가?","JPN":"まさかホライズンがあの数を全員殺したと？　それを今僕に信じろというのか？","ENG":"You mean to tell me Horizon took on all of them? You expect me to believe such nonsense?","TWN":"難道是地平線一個打一百個嗎？你覺得我會相信嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응. 믿는 편이 그쪽한테 장기적으로는 더 좋을 거야.","JPN":"そうね、長期的な目でみれば信じたほうがあなたのためになると思うわ。","ENG":"Yeah. And believing that would be to your benefit in the long run.","TWN":"嗯。就長遠來看，你還是相信會比較好。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"웃기지 마라. 보나마나 코핀 컴퍼니가 지원해 줬겠지.","JPN":"ふざけるな。どうせコフィンカンパニーが介入したんだろ。","ENG":"Don't be ridiculous. I'm sure the Coffin Company backed her up.","TWN":"笑死，用膝蓋想也知道科芬公司一定有幫忙吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"일개 사채업자 따위가 첨단 강화복을 입은 현역 용병들에 기갑 병기까지 때려눕혔다고?","JPN":"一介の闇金業者が、最新型の強化服を着た現役の傭兵たちを、しかも機甲兵器まで倒しただと？","ENG":"Some lowlife loan shark couldn't possibly take out mercenaries in power suits with armored weapon systems.","TWN":"不過就是個放高利貸的，竟然可以打倒穿著尖端強化服的現役傭兵，甚至是機甲兵器？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그 마피아 같은 여자만 아니었어도 진즉 뒈져서 고철 처리됐을 주제에?","JPN":"あのマフィアみたいな女がいなかったら、とっくの昔にくたばって鉄くずになってたはずのものが？","ENG":"If it wasn't for that mafia lady, that piece of junk would've been sold for scraps long ago.","TWN":"要不是有那個像黑手黨一樣的女人，我看她早就成破銅爛鐵！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"차라리 네가 사실은 인간을 사랑한다고 해.","JPN":"君から「実は人間のことが大好きだ」とでも言われた方がまだ信じられるが。","ENG":"I'd find it more believable if you said you actually love humans.","TWN":"你不如乾脆跟我說你其實很喜歡人類。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 믿기 싫으면 말고. 나야 자주 볼수록 더 좋으니까.","JPN":"まあ、信じないなら別にいいわ。私もまたあの子に会いたいし。","ENG":"Well, it's your choice if you don't want to believe me. If anything, I'd be happy to see her more often.","TWN":"好吧，不信就算了。反正越常見到她我越開心。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……잠깐, 타격조는 분명 의료 지원을 핑계로 투입했겠지?","JPN":"……待て、突撃隊は確か医療奉仕を口実に投入したな？","ENG":"…Hang on. Did the strike squads use the medical aid as cover?","TWN":"……等等，打擊組是用義診的名義進去的，沒錯吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응. 항상 하던 대로 말이야.","JPN":"そうよ、いつもどおりね。","ENG":"Yeah. As usual.","TWN":"嗯，跟之前一樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"마침 잘됐군. 샤레이드의 도시 관리국에 연락해야겠어.","JPN":"ちょうどよかった。シャレードの都市管理局に連絡を入れよう。","ENG":"Perfect. I'd better give the Charade City Managements a call.","TWN":"很好，那我要聯絡一下查雷德的城市管理局。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"한때 무법자로 설치던 사채업자가 의료 지원을 나온 선량한 우리 직원들에게 테러를 가했다……","JPN":"かつて街を荒らしていた闇金業者が、医療奉仕で来た善良な我が社の社員に手を出した……","ENG":"An outlaw loan shark launched a terrorist attack on our innocent employees offering medical relief to the needy…","TWN":"為非作歹的的高利貸業者，對我們公司派來義診的善良員工施暴……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어때, 매력적인 문구 아냐?","JPN":"どうだ、魅力的なニュースじゃないか？","ENG":"That will raise more than a few eyebrows, don't you think?","TWN":"怎麼樣？很聳動的內容吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>회사에 금전을 요구하면서</color>, 라는 말도 빠뜨리지 마. 대표님.","JPN":"<color=#ffd34c>会社に金銭を要求しながら</color>という言葉も欠かさないでね、代表。","ENG":"Don't forget to add how she <color=#ffd34c>demanded money from the company</color> while holding our folks hostage, boss.","TWN":"<color=#ffd34c>而且還勒索公司</color>，這個也要記得加進去。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};